def solve(digits):
    if not digits: return 0
    phone = {'2':'abc','3':'def','4':'ghi','5':'jkl','6':'mno','7':'pqrs','8':'tuv','9':'wxyz'}
    res = []
    def bt(idx, path):
        if idx == len(digits):
            res.append(''.join(path))
            return
        for c in phone[digits[idx]]:
            path.append(c)
            bt(idx+1, path)
            path.pop()
    bt(0, [])
    return len(res)

